// Parse the structured JSON from OpenAI and flatten it for downstream nodes.
const raw = $input.first().json;
const choice = raw.choices?.[0]?.message?.content;

let parsed;
try {
  parsed = JSON.parse(choice);
} catch {
  throw new Error('OpenAI did not return valid JSON. Raw response: ' + choice);
}

const client = parsed.client || {};
const classification = parsed.classification || {};
const matter = parsed.matter || {};

return [{
  json: {
    // Flat fields for easy use in downstream nodes
    clientName: client.full_name || 'Unknown',
    clientFirstName: client.first_name || '',
    clientLastName: client.last_name || '',
    clientEmail: client.email || null,
    clientPhone: client.phone || null,
    clientDob: client.date_of_birth || null,
    clientCountryOfCitizenship: client.country_of_citizenship || null,
    clientCurrentStatus: client.current_immigration_status || null,

    matterDescription: matter.description || `${classification.visa_category || 'Immigration'} — ${client.full_name || 'New Client'}`,
    matterStatus: matter.status || 'Pending',

    visaCategory: classification.visa_category || 'UNCLEAR',
    visaSubcategory: classification.visa_subcategory || null,
    confidence: classification.confidence || 'LOW',
    reasoning: classification.reasoning || '',
    alternativePathways: (classification.alternative_pathways || []).join(', '),

    documentChecklistText: (parsed.document_checklist || []).map((item, i) => `${i + 1}. ${item}`).join('\n'),
    urgency: parsed.urgency || 'ROUTINE',
    notes: parsed.notes || '',

    // Keep the full parsed object for reference
    aiParsed: parsed
  }
}];
